import type { Metadata } from "next"
import LearningProgressScreen from "./LearningProgressScreen"

export const metadata: Metadata = {
  title: "学習進捗ダッシュボード — 中2 数学 / 2年A組",
  description:
    "クラスのコース進捗・課題提出状況・到達度（習熟）を一画面で把握し、要支援の学習者を早期に発見するための学習進捗ダッシュボード。",
}

export default function LearningProgressPage() {
  return <LearningProgressScreen />
}

// Mock data for the 学習進捗 / LMS ダッシュボード.
// Course: 「中2 数学 — 1次関数〜図形」, クラス: 2年A組 (28名想定だが、ここでは代表 8名)

export type SubmissionStatus = "graded" | "submitted" | "missing" | "overdue"

export interface Unit {
  id: string
  /** 単元番号 (e.g. "第1章") */
  no: string
  title: string
  /** クラス平均の完了率 (0–100) */
  classCompletion: number
  lessons: number
}

export interface Assignment {
  id: string
  title: string
  /** 期限 (表示用) */
  due: string
  /** 期限超過の課題か */
  pastDue: boolean
}

export interface Student {
  id: string
  name: string
  furigana: string
  /** コース全体の進捗率 (0–100) */
  progress: number
  /** 到達度（習熟）スコア 0–100。target=80 が到達ライン。 */
  mastery: number
  /** ログイン/学習の最終アクティビティ */
  lastActive: string
  /** 今週の学習時間（分） */
  weeklyMinutes: number
  /** 課題ごとの提出状況 (assignment.id -> status) */
  submissions: Record<string, SubmissionStatus>
}

export interface Objective {
  id: string
  /** 学習到達目標 */
  label: string
  /** クラスの到達度（%） */
  classMastery: number
  /** 到達ライン (%) */
  target: number
}

export const COURSE = {
  title: "中2 数学 — 1次関数と図形の証明",
  className: "2年A組",
  term: "2026年度 1学期",
  teacher: "村上 拓海",
  studentCount: 28,
  /** 到達ライン（習熟）。これ以上で「到達」。 */
  masteryTarget: 80,
}

export const UNITS: Unit[] = [
  { id: "u1", no: "第1章", title: "1次関数の式とグラフ", classCompletion: 96, lessons: 6 },
  { id: "u2", no: "第2章", title: "連立方程式の利用", classCompletion: 88, lessons: 5 },
  { id: "u3", no: "第3章", title: "1次関数と図形", classCompletion: 64, lessons: 7 },
  { id: "u4", no: "第4章", title: "平行と合同", classCompletion: 41, lessons: 6 },
  { id: "u5", no: "第5章", title: "三角形・四角形の証明", classCompletion: 12, lessons: 8 },
]

export const ASSIGNMENTS: Assignment[] = [
  { id: "a1", title: "1次関数 確認ドリル", due: "5/12", pastDue: true },
  { id: "a2", title: "連立方程式 文章題", due: "5/19", pastDue: true },
  { id: "a3", title: "図形と関数 レポート", due: "5/26", pastDue: true },
  { id: "a4", title: "合同条件 小テスト", due: "6/02", pastDue: false },
  { id: "a5", title: "証明 記述課題", due: "6/09", pastDue: false },
]

export const STUDENTS: Student[] = [
  {
    id: "s1", name: "青木 さくら", furigana: "あおき さくら",
    progress: 92, mastery: 88, lastActive: "本日", weeklyMinutes: 210,
    submissions: { a1: "graded", a2: "graded", a3: "graded", a4: "submitted", a5: "missing" },
  },
  {
    id: "s2", name: "井上 蓮", furigana: "いのうえ れん",
    progress: 78, mastery: 74, lastActive: "1日前", weeklyMinutes: 140,
    submissions: { a1: "graded", a2: "graded", a3: "submitted", a4: "submitted", a5: "missing" },
  },
  {
    id: "s3", name: "遠藤 美咲", furigana: "えんどう みさき",
    progress: 34, mastery: 41, lastActive: "8日前", weeklyMinutes: 15,
    submissions: { a1: "graded", a2: "overdue", a3: "missing", a4: "missing", a5: "missing" },
  },
  {
    id: "s4", name: "加藤 大輝", furigana: "かとう だいき",
    progress: 61, mastery: 66, lastActive: "2日前", weeklyMinutes: 95,
    submissions: { a1: "graded", a2: "graded", a3: "overdue", a4: "submitted", a5: "missing" },
  },
  {
    id: "s5", name: "佐々木 結衣", furigana: "ささき ゆい",
    progress: 88, mastery: 91, lastActive: "本日", weeklyMinutes: 190,
    submissions: { a1: "graded", a2: "graded", a3: "graded", a4: "graded", a5: "submitted" },
  },
  {
    id: "s6", name: "田中 颯太", furigana: "たなか そうた",
    progress: 22, mastery: 33, lastActive: "12日前", weeklyMinutes: 0,
    submissions: { a1: "overdue", a2: "missing", a3: "missing", a4: "missing", a5: "missing" },
  },
  {
    id: "s7", name: "中村 葵", furigana: "なかむら あおい",
    progress: 70, mastery: 79, lastActive: "本日", weeklyMinutes: 165,
    submissions: { a1: "graded", a2: "graded", a3: "graded", a4: "submitted", a5: "missing" },
  },
  {
    id: "s8", name: "山本 陽菜", furigana: "やまもと ひな",
    progress: 55, mastery: 58, lastActive: "4日前", weeklyMinutes: 60,
    submissions: { a1: "graded", a2: "submitted", a3: "overdue", a4: "missing", a5: "missing" },
  },
]

export const OBJECTIVES: Objective[] = [
  { id: "o1", label: "1次関数の変化の割合を求められる", classMastery: 89, target: 80 },
  { id: "o2", label: "連立方程式を文章題に適用できる", classMastery: 82, target: 80 },
  { id: "o3", label: "グラフと図形の交点を座標で求められる", classMastery: 71, target: 80 },
  { id: "o4", label: "三角形の合同条件を説明できる", classMastery: 63, target: 80 },
  { id: "o5", label: "図形の性質を根拠を示して証明できる", classMastery: 48, target: 80 },
]

// 週次の学習活動（クラス合計の学習時間・時間換算）と平均進捗率の推移
export const WEEKLY_ACTIVITY = [
  { week: "4/W1", hours: 38, avgProgress: 8 },
  { week: "4/W2", hours: 52, avgProgress: 19 },
  { week: "4/W3", hours: 47, avgProgress: 31 },
  { week: "5/W1", hours: 61, avgProgress: 44 },
  { week: "5/W2", hours: 44, avgProgress: 53 },
  { week: "5/W3", hours: 33, avgProgress: 58 },
  { week: "6/W1", hours: 40, avgProgress: 62 },
]

export const STATUS_META: Record<
  SubmissionStatus,
  { label: string; short: string }
> = {
  graded: { label: "採点済", short: "済" },
  submitted: { label: "提出済", short: "提" },
  overdue: { label: "期限切れ", short: "限" },
  missing: { label: "未提出", short: "未" },
}

"use client"

import * as React from "react"
import {
  IconAlertTriangle,
  IconCheck,
  IconChevronRight,
  IconClock,
  IconClockExclamation,
  IconFileCheck,
  IconFileText,
  IconProgressCheck,
  IconUserExclamation,
  IconX,
} from "@tabler/icons-react"
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Avatar,
  AvatarFallback,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Container,
  DataTable,
  DistributionBar,
  Grid,
  HStack,
  LineChart,
  Meter,
  Progress,
  ScheduleGrid,
  Sheet,
  SheetClose,
  SheetContent,
  SheetDescription,
  SheetFooter,
  SheetHeader,
  SheetTitle,
  Statistic,
  Tabs,
  TabsContent,
  TabsList,
  TabsTrigger,
  VStack,
  type ColumnDef,
  type ScheduleCell,
} from "@gunjo/ui"
import {
  ASSIGNMENTS,
  COURSE,
  OBJECTIVES,
  STATUS_META,
  STUDENTS,
  UNITS,
  WEEKLY_ACTIVITY,
  type Student,
  type SubmissionStatus as Status,
} from "./data"

/* ---------- helpers ---------- */

const pct = (n: number) => `${Math.round(n)}%`

// 提出状況 → アイコン + 色だけに頼らない Badge variant のマッピング
const STATUS_BADGE: Record<
  Status,
  { variant: "success" | "info" | "warning" | "destructive" | "secondary"; icon: React.ReactNode; tone: "success" | "info" | "warning" | "destructive" }
> = {
  graded: { variant: "success", icon: <IconFileCheck />, tone: "success" },
  submitted: { variant: "info", icon: <IconCheck />, tone: "info" },
  overdue: { variant: "destructive", icon: <IconClockExclamation />, tone: "destructive" },
  missing: { variant: "warning", icon: <IconX />, tone: "warning" },
}

// 各課題の提出率（採点済 or 提出済 を「提出あり」とみなす）
function submissionRate(assignmentId: string) {
  const submitted = STUDENTS.filter((s) => {
    const st = s.submissions[assignmentId]
    return st === "graded" || st === "submitted"
  }).length
  return Math.round((submitted / STUDENTS.length) * 100)
}

// 提出状況の内訳（DistributionBar 用）
function statusBreakdown(assignmentId: string) {
  const counts: Record<Status, number> = { graded: 0, submitted: 0, missing: 0, overdue: 0 }
  for (const s of STUDENTS) counts[s.submissions[assignmentId]]++
  return counts
}

// 要支援判定：進捗 < 50% / 習熟 < 到達ライン / 期限切れ提出あり
function riskReasons(s: Student): string[] {
  const reasons: string[] = []
  if (s.progress < 50) reasons.push(`進捗 ${pct(s.progress)}`)
  if (s.mastery < COURSE.masteryTarget) reasons.push(`習熟 ${pct(s.mastery)}（到達ライン ${COURSE.masteryTarget}%未満）`)
  const overdue = Object.values(s.submissions).filter((st) => st === "overdue").length
  const missing = Object.values(s.submissions).filter((st) => st === "missing").length
  if (overdue > 0) reasons.push(`期限切れ ${overdue}件`)
  if (missing >= 3) reasons.push(`未提出 ${missing}件`)
  if (s.weeklyMinutes === 0) reasons.push("今週の学習なし")
  return reasons
}

const atRisk = STUDENTS.map((s) => ({ student: s, reasons: riskReasons(s) }))
  .filter((r) => r.reasons.length >= 2)
  .sort((a, b) => a.student.progress - b.student.progress)

/* ---------- KPI 集計 ---------- */

const classAvgProgress = Math.round(
  STUDENTS.reduce((a, s) => a + s.progress, 0) / STUDENTS.length
)
const classAvgMastery = Math.round(
  STUDENTS.reduce((a, s) => a + s.mastery, 0) / STUDENTS.length
)
const overallSubmissionRate = Math.round(
  ASSIGNMENTS.reduce((a, x) => a + submissionRate(x.id), 0) / ASSIGNMENTS.length
)
const masteredCount = STUDENTS.filter((s) => s.mastery >= COURSE.masteryTarget).length

/* ---------- 提出状況マトリクス (students × assignments) ---------- */

function StatusBadge({ status, full = false }: { status: Status; full?: boolean }) {
  const meta = STATUS_META[status]
  const cfg = STATUS_BADGE[status]
  return (
    <Badge variant={cfg.variant} icon={cfg.icon}>
      {full ? meta.label : meta.short}
    </Badge>
  )
}

/* ---------- main ---------- */

export default function LearningProgressScreen() {
  const [selected, setSelected] = React.useState<Student | null>(null)

  // ScheduleGrid: 行 = 生徒、列 = 課題
  const gridRows = STUDENTS.map((s) => ({
    id: s.id,
    label: s.name,
    sublabel: pct(s.progress),
    ariaLabel: s.name,
  }))
  const gridColumns = ASSIGNMENTS.map((a) => ({
    id: a.id,
    label: a.title,
    sublabel: `期限 ${a.due}・提出 ${submissionRate(a.id)}%`,
    ariaLabel: a.title,
  }))
  const gridCells: ScheduleCell[] = STUDENTS.flatMap((s) =>
    ASSIGNMENTS.map((a) => {
      const status = s.submissions[a.id]
      return {
        rowId: s.id,
        colId: a.id,
        tone: STATUS_BADGE[status].tone,
        description: STATUS_META[status].label,
        content: (
          <div className="flex items-center justify-center">
            <StatusBadge status={status} />
          </div>
        ),
        onSelect: () => setSelected(s),
      } satisfies ScheduleCell
    })
  )

  // 課題テーブル
  const assignmentColumns: ColumnDef<(typeof ASSIGNMENTS)[number]>[] = [
    {
      accessorKey: "title",
      header: "課題",
      cell: ({ row }) => (
        <div className="flex items-center gap-2">
          <IconFileText className="h-4 w-4 shrink-0 text-muted-foreground" aria-hidden />
          <span className="font-medium">{row.original.title}</span>
        </div>
      ),
    },
    {
      accessorKey: "due",
      header: "期限",
      cell: ({ row }) => (
        <span className="inline-flex items-center gap-1 tabular-nums text-muted-foreground">
          <IconClock className="h-3.5 w-3.5" aria-hidden />
          {row.original.due}
          {row.original.pastDue ? <span className="sr-only">（期限超過）</span> : null}
        </span>
      ),
    },
    {
      id: "rate",
      header: "提出率",
      cell: ({ row }) => {
        const rate = submissionRate(row.original.id)
        return (
          <div className="min-w-[120px] max-w-[180px]">
            <Meter
              value={rate}
              max={100}
              target={70}
              direction="higher-is-better"
              size="inline"
              unit="%"
              label={`${row.original.title} の提出率`}
            />
          </div>
        )
      },
    },
    {
      id: "breakdown",
      header: "内訳",
      cell: ({ row }) => {
        const c = statusBreakdown(row.original.id)
        return (
          <div className="min-w-[160px] max-w-[260px]">
            <DistributionBar
              segments={[
                { label: STATUS_META.graded.label, value: c.graded, color: "success" },
                { label: STATUS_META.submitted.label, value: c.submitted, color: "info" },
                { label: STATUS_META.overdue.label, value: c.overdue, color: "destructive" },
                { label: STATUS_META.missing.label, value: c.missing, color: "warning" },
              ]}
            />
          </div>
        )
      },
    },
  ]

  return (
    <main className="min-h-screen bg-background pb-20">
      <Container size="xl" className="py-6 sm:py-8">
        <VStack gap={6} align="stretch">
          {/* ===== ヘッダ ===== */}
          <header>
            <p className="text-sm text-muted-foreground">
              {COURSE.term}・担当 {COURSE.teacher} 先生
            </p>
            <h1 className="mt-1 text-2xl font-bold tracking-tight sm:text-3xl">
              学習進捗ダッシュボード
            </h1>
            <p className="mt-1 text-base text-muted-foreground">
              {COURSE.title}（{COURSE.className}・{COURSE.studentCount}名）
            </p>
          </header>

          {/* ===== 要支援アラート ===== */}
          {atRisk.length > 0 ? (
            <Alert variant="warning">
              <IconUserExclamation className="h-4 w-4" aria-hidden />
              <AlertTitle as="h2">
                要支援の学習者が {atRisk.length} 名います
              </AlertTitle>
              <AlertDescription>
                進捗の遅れ・習熟の不足・課題の未提出が重なっている生徒を下の「要支援の学習者」で確認し、声かけや個別指導の対象を検討してください。
              </AlertDescription>
            </Alert>
          ) : null}

          {/* ===== KPI ===== */}
          <section aria-labelledby="kpi-heading">
            <h2 id="kpi-heading" className="sr-only">
              クラスの概況
            </h2>
            <Grid minItemWidth={200} gap={4}>
              <Statistic
                label="クラス平均進捗"
                value={pct(classAvgProgress)}
                change="先週 +4pt"
                trend="up"
                hint="コース全体"
              />
              <Statistic
                label="平均習熟（到達度）"
                value={pct(classAvgMastery)}
                change={`到達ライン ${COURSE.masteryTarget}%`}
                trend={classAvgMastery >= COURSE.masteryTarget ? "up" : "down"}
                tone={classAvgMastery >= COURSE.masteryTarget ? "positive" : "negative"}
                hint={`到達 ${masteredCount}/${STUDENTS.length}名`}
              />
              <Statistic
                label="課題提出率（平均）"
                value={pct(overallSubmissionRate)}
                change="全5課題"
                trend="flat"
                hint="採点済＋提出済"
              />
              <Statistic
                label="要支援の学習者"
                value={`${atRisk.length}名`}
                change="要フォロー"
                trend="down"
                tone="negative"
                hint="複数条件に該当"
              />
            </Grid>
          </section>

          {/* ===== コース進捗 + 学習活動推移 ===== */}
          <Grid minItemWidth={320} gap={4}>
            {/* コース進捗（単元別） */}
            <Card>
              <CardHeader>
                <CardTitle as="h2">コース進捗（単元別）</CardTitle>
                <CardDescription>
                  各章のクラス平均完了率。下にいくほど未着手の章です。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <VStack gap={4} align="stretch">
                  {UNITS.map((u) => (
                    <div key={u.id}>
                      <div className="mb-1 flex items-baseline justify-between gap-2">
                        <span className="text-sm font-medium">
                          <span className="text-muted-foreground">{u.no}</span>{" "}
                          {u.title}
                        </span>
                        <span className="shrink-0 text-xs text-muted-foreground tabular-nums">
                          {u.lessons}レッスン
                        </span>
                      </div>
                      <HStack gap={3} align="center">
                        <div className="min-w-0 flex-1">
                          <Progress
                            value={u.classCompletion}
                            label={`${u.title} の完了率`}
                            valueText={`完了 ${pct(u.classCompletion)}`}
                            tone={
                              u.classCompletion >= 80
                                ? "success"
                                : u.classCompletion >= 40
                                ? "primary"
                                : "warning"
                            }
                          />
                        </div>
                        <span className="w-10 shrink-0 text-right text-sm font-semibold tabular-nums">
                          {pct(u.classCompletion)}
                        </span>
                      </HStack>
                    </div>
                  ))}
                </VStack>
              </CardContent>
            </Card>

            {/* 学習活動の推移 */}
            <Card>
              <CardHeader>
                <CardTitle as="h2">学習活動の推移（週次）</CardTitle>
                <CardDescription>
                  クラスの学習時間（時間）と平均進捗率の推移。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <LineChart
                  series={[
                    {
                      label: "平均進捗率(%)",
                      color: "primary",
                      data: WEEKLY_ACTIVITY.map((w) => ({
                        label: w.week,
                        value: w.avgProgress,
                      })),
                    },
                    {
                      label: "学習時間(h)",
                      color: "info",
                      data: WEEKLY_ACTIVITY.map((w) => ({
                        label: w.week,
                        value: w.hours,
                      })),
                    },
                  ]}
                  showGrid
                  showDots
                  showLegend
                  showLabels
                  min={0}
                />
                <p className="mt-2 text-xs text-muted-foreground">
                  ※ 学習時間は GW（5/W2〜W3）で一時的に低下。新章（証明）開始に伴い再び上昇傾向。
                </p>
              </CardContent>
            </Card>
          </Grid>

          {/* ===== 課題提出状況（テーブル + マトリクス） ===== */}
          <Card>
            <CardHeader>
              <CardTitle as="h2">課題提出状況</CardTitle>
              <CardDescription>
                課題ごとの提出率と、生徒×課題の提出マトリクス。状態はアイコン＋ラベルで表示しています（色のみに依存しません）。
              </CardDescription>
            </CardHeader>
            <CardContent>
              <Tabs defaultValue="list">
                <TabsList>
                  <TabsTrigger value="list">課題一覧</TabsTrigger>
                  <TabsTrigger value="matrix">提出マトリクス</TabsTrigger>
                </TabsList>

                <TabsContent value="list" className="pt-4">
                  <DataTable
                    columns={assignmentColumns}
                    data={ASSIGNMENTS}
                    filter={null}
                    pageSize={10}
                  />
                </TabsContent>

                <TabsContent value="matrix" className="pt-4">
                  {/* 凡例 */}
                  <div className="mb-3 flex flex-wrap items-center gap-x-4 gap-y-2">
                    <span className="text-xs font-medium text-muted-foreground">
                      凡例:
                    </span>
                    {(Object.keys(STATUS_META) as Status[]).map((st) => (
                      <StatusBadge key={st} status={st} full />
                    ))}
                  </div>
                  <ScheduleGrid
                    label="生徒ごとの課題提出状況マトリクス"
                    cornerLabel="生徒 \ 課題"
                    rows={gridRows}
                    columns={gridColumns}
                    cells={gridCells}
                    rowHeaderWidth={104}
                    minColumnWidth={132}
                  />
                  <p className="mt-2 text-xs text-muted-foreground">
                    セルを選択（クリック / Enter）すると生徒の詳細を開けます。矢印キーでセル間を移動できます。
                  </p>
                </TabsContent>
              </Tabs>
            </CardContent>
          </Card>

          {/* ===== 到達度 / 習熟 + 要支援 ===== */}
          <Grid minItemWidth={320} gap={4}>
            {/* 学習到達目標ごとの習熟（到達ライン判定） */}
            <Card>
              <CardHeader>
                <CardTitle as="h2">到達度 / 習熟（学習目標別）</CardTitle>
                <CardDescription>
                  到達ライン {COURSE.masteryTarget}% に対するクラスの到達度。ラインのマーカーより手前は要強化です。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <VStack gap={4} align="stretch">
                  {OBJECTIVES.map((o) => {
                    const below = o.classMastery < o.target
                    return (
                      <div key={o.id}>
                        <div className="mb-1 flex items-start justify-between gap-2">
                          <span className="text-sm font-medium">{o.label}</span>
                          {below ? (
                            <Badge
                              variant="warning"
                              icon={<IconAlertTriangle />}
                              className="shrink-0"
                            >
                              到達ライン未満
                            </Badge>
                          ) : (
                            <Badge
                              variant="success"
                              icon={<IconCheck />}
                              className="shrink-0"
                            >
                              到達
                            </Badge>
                          )}
                        </div>
                        <Meter
                          value={o.classMastery}
                          max={100}
                          target={o.target}
                          direction="higher-is-better"
                          unit="%"
                          label={`${o.label} の到達度`}
                        />
                      </div>
                    )
                  })}
                </VStack>
              </CardContent>
            </Card>

            {/* 要支援の学習者 */}
            <Card>
              <CardHeader>
                <CardTitle as="h2">
                  要支援の学習者
                </CardTitle>
                <CardDescription>
                  進捗・習熟・提出のうち複数が基準を下回る生徒。進捗の低い順。
                </CardDescription>
              </CardHeader>
              <CardContent>
                <ul className="divide-y divide-border">
                  {atRisk.map(({ student, reasons }) => (
                    <li
                      key={student.id}
                      className="flex items-center gap-3 py-3 first:pt-0 last:pb-0"
                    >
                      <Avatar className="h-9 w-9 shrink-0">
                        <AvatarFallback>{student.name.slice(0, 1)}</AvatarFallback>
                      </Avatar>
                      <div className="min-w-0 flex-1">
                        <div className="flex items-center gap-2">
                          <span className="truncate font-medium">{student.name}</span>
                          <span className="shrink-0 text-xs text-muted-foreground">
                            最終学習 {student.lastActive}
                          </span>
                        </div>
                        <div className="mt-1 flex flex-wrap gap-1">
                          {reasons.map((r, i) => (
                            <Badge
                              key={i}
                              variant={i === 0 ? "destructive" : "warning"}
                              icon={<IconAlertTriangle />}
                            >
                              {r}
                            </Badge>
                          ))}
                        </div>
                      </div>
                      <Button
                        variant="outline"
                        size="sm"
                        className="shrink-0"
                        onClick={() => setSelected(student)}
                      >
                        詳細
                        <IconChevronRight className="ml-1 h-4 w-4" aria-hidden />
                      </Button>
                    </li>
                  ))}
                </ul>
              </CardContent>
            </Card>
          </Grid>
        </VStack>
      </Container>

      {/* ===== 生徒詳細 Sheet ===== */}
      <Sheet open={selected !== null} onOpenChange={(o) => !o && setSelected(null)}>
        <SheetContent side="right" className="w-full max-w-md">
          {selected ? (
            <>
              <SheetHeader>
                <SheetTitle>{selected.name}</SheetTitle>
                <SheetDescription>
                  {selected.furigana}・{COURSE.className}・最終学習 {selected.lastActive}
                </SheetDescription>
              </SheetHeader>

              <div className="space-y-6 px-4 py-4">
                <Grid cols={2} gap={3}>
                  <Statistic label="コース進捗" value={pct(selected.progress)} />
                  <Statistic
                    label="習熟（到達度）"
                    value={pct(selected.mastery)}
                    tone={selected.mastery >= COURSE.masteryTarget ? "positive" : "negative"}
                    trend={selected.mastery >= COURSE.masteryTarget ? "up" : "down"}
                    change={selected.mastery >= COURSE.masteryTarget ? "到達" : "未到達"}
                  />
                </Grid>

                <div>
                  <h3 className="mb-2 flex items-center gap-1.5 text-sm font-semibold">
                    <IconProgressCheck className="h-4 w-4 text-muted-foreground" aria-hidden />
                    到達度（到達ライン {COURSE.masteryTarget}%）
                  </h3>
                  <Meter
                    value={selected.mastery}
                    max={100}
                    target={COURSE.masteryTarget}
                    direction="higher-is-better"
                    unit="%"
                    label={`${selected.name} の到達度`}
                  />
                </div>

                <div>
                  <h3 className="mb-2 text-sm font-semibold">課題提出状況</h3>
                  <ul className="space-y-2">
                    {ASSIGNMENTS.map((a) => (
                      <li
                        key={a.id}
                        className="flex items-center justify-between gap-2 text-sm"
                      >
                        <span className="truncate text-muted-foreground">
                          {a.title}
                        </span>
                        <StatusBadge status={selected.submissions[a.id]} full />
                      </li>
                    ))}
                  </ul>
                </div>

                <div>
                  <h3 className="mb-2 text-sm font-semibold">今週の学習時間</h3>
                  <p className="text-sm tabular-nums">
                    {selected.weeklyMinutes} 分
                    {selected.weeklyMinutes === 0 ? (
                      <span className="ml-2 text-destructive">（学習記録なし）</span>
                    ) : null}
                  </p>
                </div>

                {riskReasons(selected).length > 0 ? (
                  <Alert variant="warning">
                    <IconAlertTriangle className="h-4 w-4" aria-hidden />
                    <AlertTitle as="h3">フォローのポイント</AlertTitle>
                    <AlertDescription>
                      <ul className="mt-1 list-inside list-disc">
                        {riskReasons(selected).map((r, i) => (
                          <li key={i}>{r}</li>
                        ))}
                      </ul>
                    </AlertDescription>
                  </Alert>
                ) : null}
              </div>

              <SheetFooter>
                <Button className="w-full">メッセージを送る</Button>
                <SheetClose asChild>
                  <Button variant="outline" className="w-full">
                    閉じる
                  </Button>
                </SheetClose>
              </SheetFooter>
            </>
          ) : null}
        </SheetContent>
      </Sheet>
    </main>
  )
}
